"use client";

import { useState, useEffect } from "react";
import { useSignIn } from "@clerk/nextjs";
import { useRouter } from "next/navigation";
import { Shield, Lock, User, ChevronRight, Command } from "lucide-react";
import Link from "next/link";
import { motion } from "framer-motion";

export default function AdminLoginPage() {
  const { isLoaded, signIn, setActive } = useSignIn() as any;
  const [identifier, setIdentifier] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const router = useRouter();

  // Redirect if already has session
  useEffect(() => {
    if (typeof window !== "undefined") {
      const session = sessionStorage.getItem("admin_session");
      if (session === "active") {
        router.push("/admin");
      }
    }
  }, [router]);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!isLoaded || !signIn) return;
    
    setLoading(true);
    setError("");

    try {
      const result = await signIn.create({
        identifier,
        password,
      });

      if (result.status === "complete") {
        if (setActive) {
          await setActive({ session: result.createdSessionId });
          
          // After setting active, we set our sessionStorage flag to satisfy "auto logout on tab close"
          sessionStorage.setItem("admin_session", "active");
          
          // Small delay to ensure Clerk session is propagated before redirecting
          setTimeout(() => {
            router.push("/admin");
          }, 1000);
        }
      } else {
        setError("Your account requires additional verification. Please use the standard login.");
      }
    } catch (err: any) {
      console.error("Clerk Login Error:", err);
      setError(err.errors?.[0]?.message || "Invalid administrative credentials");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4 font-sans">
      <div className="max-w-md w-full">
        {/* Logo/Header */}
        <div className="text-center mb-10 animate-fade-in">
          <div className="inline-flex items-center justify-center size-16 bg-primary rounded-2xl shadow-xl shadow-primary/20 mb-6 text-white text-3xl font-black">
            <Command className="size-8" />
          </div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tighter">Admin Portal</h1>
          <p className="text-slate-500 font-bold uppercase tracking-[0.2em] text-[10px] mt-2">
            Secure Infrastructure Gateway
          </p>
        </div>

        {/* Login Card */}
        <motion.div 
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className="bg-white rounded-[32px] p-8 md:p-10 shadow-2xl shadow-slate-200 border border-slate-100 relative overflow-hidden"
        >
          <div className="absolute top-0 right-0 w-32 h-32 bg-primary/5 rounded-full blur-3xl -mr-16 -mt-16"></div>
          
          <form onSubmit={handleLogin} className="space-y-6 relative z-10">
            <div>
              <label className="block text-[10px] font-black text-slate-700 mb-3 uppercase tracking-widest">Administrative ID</label>
              <div className="relative group">
                <User className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-primary transition-colors size-5" />
                <input
                  type="text"
                  value={identifier}
                  onChange={(e) => setIdentifier(e.target.value)}
                  placeholder="Email or Username"
                  required
                  className="w-full pl-12 pr-6 py-3.5 rounded-2xl border-2 border-slate-100 bg-slate-50/50 focus:bg-white focus:border-primary focus:ring-8 focus:ring-primary/5 transition-all outline-none font-bold"
                />
              </div>
            </div>

            <div>
              <label className="block text-[10px] font-black text-slate-700 mb-3 uppercase tracking-widest">Security Key</label>
              <div className="relative group">
                <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-primary transition-colors size-5" />
                <input
                  type="password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  placeholder="Enter your password"
                  required
                  className="w-full pl-12 pr-6 py-3.5 rounded-2xl border-2 border-slate-100 bg-slate-50/50 focus:bg-white focus:border-primary focus:ring-8 focus:ring-primary/5 transition-all outline-none font-bold"
                />
              </div>
            </div>

            {error && (
              <p className="text-rose-500 text-xs font-bold text-center bg-rose-50 py-2 rounded-lg border border-rose-100 animate-shake">
                {error}
              </p>
            )}

            <button
              type="submit"
              disabled={loading || !isLoaded}
              className="w-full bg-slate-900 hover:bg-slate-800 text-white font-black py-4 rounded-2xl shadow-xl transition-all flex items-center justify-center gap-3 active:scale-[0.98] disabled:opacity-50"
            >
              {loading ? (
                <div className="size-5 border-2 border-white/20 border-t-white rounded-full animate-spin"></div>
              ) : (
                <>
                  <Shield className="size-5" />
                  Initialize Session
                </>
              )}
            </button>
          </form>

          <div className="mt-8 pt-8 border-t border-slate-100 text-center">
            <Link 
              href="/" 
              className="text-[10px] font-black text-slate-400 uppercase tracking-widest hover:text-primary transition-colors flex items-center justify-center gap-2 group"
            >
              Back to Public Site
              <ChevronRight className="size-3 group-hover:translate-x-1 transition-transform" />
            </Link>
          </div>
        </motion.div>

        {/* Footer Note */}
        <p className="text-center mt-8 text-[9px] font-black text-slate-400 uppercase tracking-[0.3em]">
          Powered by Orphosys Foundation OS v2.0
        </p>
      </div>

      <style jsx global>{`
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          10%, 30%, 50%, 70%, 90% { transform: translateX(-2px); }
          20%, 40%, 60%, 80% { transform: translateX(2px); }
        }
        .animate-shake { animation: shake 0.4s cubic-bezier(.36,.07,.19,.97) both; }
      `}</style>
    </div>
  );
}
